		private byte[] Pt3 = new byte[] {1,3,9,27,81};     // potencias de 3
		private byte[] DosPt3 = new byte[] {2,6,18,54,162};// 2 * potencias de 3 

	    public byte[]  byteCol1=new byte[] {0,0,0};
		public byte[]  byteCol2=new byte[] {0,0,0};
		

		public void ConvColumnaA3Bytes (string columna1, ref byte b1, ref byte b2, ref byte b3)
		{
			int i;

			b1 = b2=b3=0;
			columna1 +="1";
	
			for ( i=0;i<5;i++ ) 
			{ 
				if (columna1[i]=='1') {} 
				else if ( columna1[i]=='2' ) b1+=DosPt3[i];
				else  b1+=Pt3[i]; 

				if ( columna1[i+5]=='1' ) {} 
				else if ( columna1[i+5]=='2' ) b2+=DosPt3[i];
				else  b2+=Pt3[i]; 

				if ( columna1[i+10]=='1' ) {} 
				else if ( columna1[i+10]=='2' ) b3+=DosPt3[i];
				else  b3+=Pt3[i]; 
			} 
		}


		//----------propiedad para asignar los 3 bytes de la columna 1--------------
		public string col1 
		{	
			get{return Conv3BytesAColumna(byteCol1);}
			set{ConvColumnaA3Bytes (value ,ref byteCol1[0], ref byteCol1[1], ref byteCol1[2]);}
		}

		//----------propiedad para asignar los 3 bytes de la columna 2--------------
		public string col2 
		{
			get	{return Conv3BytesAColumna(byteCol2);}
			set	{ConvColumnaA3Bytes (value,ref byteCol2[0],ref byteCol2[1],ref byteCol2[2]);}
		}


		//método que calcula las coincidéncias a partir de los bytes de col1 y col2.
		public byte CalculaCoincidencias ()
		{
			return (byte)(14-TDif5T[byteCol1[0],byteCol2[0]]-TDif5T[byteCol1[1],byteCol2[1]]-TDif5T[byteCol1[2],byteCol2[2]]);
		}

		public byte CalculaCoincidenciasConCol2 (byte b1, byte b2, byte b3)
		{
			//el calculo se realiza sobre col2
			return (byte)(14-TDif5T[b1,byteCol2[0]]-TDif5T[b2,byteCol2[1]]-TDif5T[b3,byteCol2[2]]);
		}
		public byte CalculaCoincidencias (byte[] b)
		{
			//el calculo se realiza sobre col1
			return (byte)(14-TDif5T[b[0],byteCol1[0]]-TDif5T[b[1],byteCol1[1]]-TDif5T[b[2],byteCol1[2]]);
		}

		public byte CalculaCoincidencias (string columna1, string columna2)
		{
			//llamar metodo para convertir string a bytes para ambas columnas... y luego
			ConvColumnaA3Bytes (columna1,ref byteCol1[0], ref byteCol1[1], ref byteCol1[2]);
			ConvColumnaA3Bytes (columna2,ref byteCol2[0],ref byteCol2[1],ref byteCol2[2]);
			return CalculaCoincidencias ();
		}

		//método que calcula las diferéncias a partir de los bytes de col1 y col2
		public byte CalculaDiferencias ()
		{
			return (byte)(TDif5T[byteCol1[0],byteCol2[0]]+TDif5T[byteCol1[1],byteCol2[1]]+TDif5T[byteCol1[2],byteCol2[2]]);
		}

		public byte CalculaDiferenciasConCol2 (byte b1, byte b2, byte b3)
		{
			// el calculo se realiza sobre col2
			return (byte)(TDif5T[b1,byteCol2[0]]+TDif5T[b2,byteCol2[1]]+TDif5T[b3,byteCol2[2]]);
		}
		public byte CalculaDiferencias (byte[] b)
		{
			// el calculo se realiza sobre col1
			return (byte)(TDif5T[b[0],byteCol1[0]]+TDif5T[b[1],byteCol1[1]]+TDif5T[b[2],byteCol1[2]]);
		}

		//método que convierte 3 bytes en columna (string).
		public string Conv3BytesAColumna (byte b1, byte b2, byte b3)
		{
			return ConvNum1X2[b1] + ConvNum1X2[b2] + ConvNum1X2[b3].Substring (0,4);
		}

		//método que convierte 3 bytes en columna (string).
		public string Conv3BytesAColumna (byte[] b)
		{
			return ConvNum1X2[b[0]] + ConvNum1X2[b[1]] + ConvNum1X2[b[2]].Substring (0,4);
